package cl.duoc.vetcontrol.historial.controller;
import cl.duoc.vetcontrol.historial.dto.HistorialRequest; import cl.duoc.vetcontrol.historial.model.HistorialClinico; import cl.duoc.vetcontrol.historial.service.HistorialService; import jakarta.validation.Valid; import org.springframework.http.*; import org.springframework.web.bind.annotation.*; import java.util.List;
@RestController @RequestMapping("/api/v1/historiales")
public class HistorialController { private final HistorialService service; public HistorialController(HistorialService service){this.service=service;} @GetMapping public ResponseEntity<List<HistorialClinico>> all(){return ResponseEntity.ok(service.all());} @GetMapping("/{id}") public ResponseEntity<HistorialClinico> one(@PathVariable Long id){return ResponseEntity.ok(service.one(id));} @GetMapping("/mascotas/{mascotaId}") public ResponseEntity<List<HistorialClinico>> byMascota(@PathVariable Long mascotaId){return ResponseEntity.ok(service.byMascota(mascotaId));} @PostMapping public ResponseEntity<HistorialClinico> create(@Valid @RequestBody HistorialRequest r){return ResponseEntity.status(HttpStatus.CREATED).body(service.create(r));} }
